/**
 * @method 
 * @name f_PrintSlipNo_v2 
 * @description 거래명세서 출력(전표번호) -- 신대양 제지용 거래명세서 발행 
 */
scwin.f_PrintSlipNoDaeYang = async function () {

    let vCount = 0;

    if (ds_purchaseEvidenceList.getRowCount() > 0) {

        const rowCnt = ds_purchaseEvidenceList.getRowCount();
        for (let i = 0; i < rowCnt; i++) {
            if (ds_purchaseEvidenceList.getCellData(i, 'chk') == 'T') {
                vCount++;

                if (vCount > 1) {
                    $c.win.alert('명세서 발행시 한건씩 발행 가능합니다.');
                    return;
                };
            };
        };

        let slipNo;
        for (let i = 0; i < rowCnt; i++) {
            if (ds_purchaseEvidenceList.getCellData(i, 'chk') == 'T') {
                slipNo = ds_purchaseEvidenceList.getCellData(i, 'slipNo'); //선택된 ROW
                break;
            };
        };

        const data = {
            reportName: '/ds/fs/adjm/fs_401_01_07p.ozr',
            // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
            odiParam: {
                slipNo: slipNo
            },

            // OZ 뷰어에 대한 설정(상세 설정은 'oz report viewer guide.pdf'를 참조)
            viewerParam: {
                mode: 'preview', // 미리보기
            },

            // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
            formParam: {},
        }


        let options = {
            id: "ozReportPopup",
            popupName: "오즈 리포트",
            modal: true,
            type: "browserPopup",
            width: 1000,
            height: 600,
            title: "오즈 리포트"
        };

        await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", options, data);

    };

};



/**
 * @method 
 * @name f_PrintSlipNo_v2 
 * @description 거래명세서 출력(전표번호) -- 복화  거래명세서 발행 / 
 * 2019.04.10 부산지사 이소현 요청사항 : 거래명세서 여러 건 한번에 발행할수 있게 조치
 */
scwin.f_PrintSlipNoBokhwa = async function () {

    // btn_Print
    let param = '';
    let printCnt = 0;

    //거래처번호: 124992 ->  동부제철(주)
    let yCount = 0; //repBilgClntNo(124992) 인 count
    let nCount = 0; //repBilgClntNo(124992) 제외 count

    const rowCnt = ds_purchaseEvidenceList.getRowCount();

    if (rowCnt == 0) return;

    for (let i = 0; i < rowCnt; i++) {
        let rowData = ds_purchaseEvidenceList.getRowJSON(i);
        if (rowData['chk'] == 'T') {
            printCnt++;
            param = param + ',' + rowData['slipNo'];  // 전표번호

            rowData['repBilgClntNo'] == '124992' ? yCount++ : nCount++;
        };
    };

    if (printCnt == 0) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_007, ['발행할 거래명세서']);  // @을(를) 선택하십시오.
        return;
    } else {
        if (yCount > 0 && nCount > 0) {
            $c.win.alert('명세서 발행시 한건씩 발행 가능합니다.');
            return;
        };
    };


    let reportName = '';
    let odiParam = {};
    let viewerParam = {};

    if (yCount > 0) {
        reportName = '/ds/fs/adjm/fs_401_01_08_v3p.ozr';
        odiParam = { 'slipNo': param.slice(1) };
        viewerParam = { mode: 'preview' }; // 미리보기
    };

    if (nCount > 0) {
        reportName = '/ds/fs/adjm/fs_401_01_08p.ozr';
        odiParam = { 'slipNo': param.slice(1) };
        viewerParam = { mode: 'preview' }; // 미리보기
    };


    const data = {
        reportName: reportName,
        // 쿼리(ODI)에 적용할 파라미터를 설정(OZParam)
        odiParam: odiParam,
        // OZ 뷰어에 대한 설정(상세 설정은 'oz report viewer guide.pdf'를 참조)
        viewerParam: viewerParam,
        // 리포트(OZR)에 적용할 파라미터를 설정(OZFormParam)
        formParam: {},
    };

    let options = {
        id: "ozReportPopup",
        popupName: "오즈 리포트",
        modal: true,
        type: "browserPopup",
        width: 1000,
        height: 600,
        title: "오즈 리포트"
    };

    await $c.win.openPopup("/ui/cm/zz/ozreportPopup.xml", options, data);

};



/**
 * @method 
 * @name f_RunExcel 
 * @description 엑셀 다운로드
 */
scwin.f_RunExcel = async function (value) {

    switch (value) {
        case 'A':
            let countA = ds_purchaseEvidenceList.getRowCount();
            if (!(countA > 0)) {
                $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
                return;
            };
            break;

        case 'B':
            let countB = ds_purchaseCertiList.getRowCount();
            if (!(countB > 0)) {
                $c.gus.cfAlertMsg(MSG_CM_WRN_002);  // 조회결과가 존재하지 않습니다.
                return;
            }

            break;

        default:
            break;
    };


    let opt = {
        callBackParam: {
            excelValue: value,
        }
    };

    const retConfirm = await $c.win.confirm('EXCEL로 다운로드 받으시겠습니까?');
    if (!retConfirm) return;

    let gridComp = {};  // 그리드ID
    let sheetName = '';  // 생성될 엑셀 파일의 쉬트명

    switch (value) {
        case 'A':
            gridComp = gr_purchaseEvidenceList;
            sheetName = '접수완료 세금계산서';
            break;

        case 'B':
            gridComp = gr_purchaseCertiList;
            sheetName = '세금계산서 미접수 거래명세서';
            break;

        default:
            break;
    };

    let infoArr = [{
        text: sheetName,
        rowIndex: 0,
        colSpan: gridComp.getTotalCol(),
        textAlign: 'center',
        fontSize: '12px',
        fontName: '돋움체',
        color: 'black',
        bgColor: '#ffffff'
    }];

    const options = {
        sheetName: sheetName,
        fileName: sheetName + ".xlsx",
        startRowIndex: 2,
        useHeaderCheckBoxLabel: true
    };
    $c.data.downloadGridViewExcel(gridComp, options, infoArr);

};



/**
 * @method 
 * @name f_openCommonPopUp 
 * @description 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
 * @param {number} disGubun
 * @param {string} pCode
 * @param {string} pName
 * @param {string} pClose
 * @param {string} pAllSearch
 */
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    let comCodeComp, codeNameArray;
    let pDispCnt = null, pTitle = null, pWidth = null, pHidden = null,
        pWhere = null, pW = null, pH = null, pTop = null, pLeft = null,
        pExistTF = null, pWtitleSearch = null, pNoDataCloseTF = null

    switch (disGubun) {
        case 1:
            // 협력회사 팝업
            comCodeComp = udc_pchsClnt;
            codeNameArray = [ed_pchsClntNo, txt_pchsClntNm]; // 협력회사코드, 협력회사명
            break;

        case 2:
            // 매입부서 팝업
            comCodeComp = udc_pchsDept;
            codeNameArray = [ed_pchsDeptCd, txt_pchsDeptNm]; // 매입부서코드, 매입부서명
            break;

        case 3:
            // 작성자 팝업
            comCodeComp = udc_drawEmp;
            codeNameArray = [ed_drawEmpNo, txt_drawEmpNm]; // 사원번호, 사원명
            break;

        case 4:
            // 작성귀속부서 팝업
            comCodeComp = udc_drawAcctDept;
            codeNameArray = [ed_drawAcctDeptCd, txt_drawAcctDeptNm]; // 작성귀속부서코드, 작성귀속부서명
            break;

        default:
            break;
    };


    comCodeComp.cfCommonPopUp(
        (rtnList) => {
            $c.gus.cfSetReturnValue(rtnList, codeNameArray[0], codeNameArray[1]);
        },
        pCode.trim(),
        pName,
        pClose,
        pDispCnt,
        pTitle,
        pWidth,
        pHidden,
        pWhere,
        pW,
        pH,
        pTop,
        pLeft,
        pExistTF,
        pAllSearch,
        pWtitleSearch,
        pNoDataCloseTF
    );

};



/**
 * @method 
 * @name f_chkOpenCommonPopUp 
 * @description 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
 * @param {object} inObj
 * @param {object} pairObj
 * @param {number} disGubun
 * @param {string} isCode
 */
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = inObj.getValue();

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');

};



